import{_ as l,o as i,c as t,a2 as e}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"巴菲特致股东信核心总结 · 2000年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2000年/核心总结.md","filePath":"01_letters/2000年/核心总结.md"}'),r={name:"01_letters/2000年/核心总结.md"};function o(h,a,n,d,s,u){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="巴菲特致股东信核心总结-·-2000年" tabindex="-1">巴菲特致股东信核心总结 · 2000年 <a class="header-anchor" href="#巴菲特致股东信核心总结-·-2000年" aria-label="Permalink to &quot;巴菲特致股东信核心总结 · 2000年&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净值收益39.6亿美元，每股账面价值增长6.5%</li><li>过去36年每股账面价值年复合增长率23.6%</li><li>账面价值增长超过标普500指数15.6个百分点</li></ul><h2 id="年度收购-8笔重大交易" tabindex="-1">年度收购（8笔重大交易） <a class="header-anchor" href="#年度收购-8笔重大交易" aria-label="Permalink to &quot;年度收购（8笔重大交易）&quot;">​</a></h2><h3 id="已完成收购" tabindex="-1">已完成收购 <a class="header-anchor" href="#已完成收购" aria-label="Permalink to &quot;已完成收购&quot;">​</a></h3><ol><li><strong>中美能源</strong> - 76%股份（1999年签约）</li><li><strong>CORT商业服务</strong> - 3.86亿美元，租用家具领域领导者</li><li><strong>美国责任保险</strong> - 特殊风险承保商</li><li><strong>本桥珠宝</strong> - 西海岸65家门店零售商</li><li><strong>贾斯汀工业</strong> - 5.7亿美元，西部靴和砖块生产商</li><li><strong>肖氏工业</strong> - 世界最大地毯制造商，87.3%股份</li><li><strong>本杰明·摩尔涂料</strong> - 10亿美元，117年历史</li><li><strong>约翰斯·曼维尔</strong> - 18亿美元，绝缘材料领先生产商</li></ol><h3 id="收购特点" tabindex="-1">收购特点 <a class="header-anchor" href="#收购特点" aria-label="Permalink to &quot;收购特点&quot;">​</a></h3><ul><li>合计销售额约130亿美元，员工58,000人</li><li>97%现金支付，3%股票支付</li><li>未承担任何债务，股份仅增加0.33%</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金发展" tabindex="-1">浮存金发展 <a class="header-anchor" href="#浮存金发展" aria-label="Permalink to &quot;浮存金发展&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>浮存金（百万美元）</th></tr></thead><tbody><tr><td>1967</td><td>20</td></tr><tr><td>1987</td><td>1,508</td></tr><tr><td>1997</td><td>7,386</td></tr><tr><td>2000</td><td>27,871</td></tr></tbody></table><h3 id="浮存金成本" tabindex="-1">浮存金成本 <a class="header-anchor" href="#浮存金成本" aria-label="Permalink to &quot;浮存金成本&quot;">​</a></h3><ul><li>2000年承保亏损16亿美元，成本6%</li><li>阿吉特·贾恩承保24亿美元再保险保费（可能创历史记录）</li><li>通用再保险定价开始修正</li></ul><h2 id="盖可保险挑战" tabindex="-1">盖可保险挑战 <a class="header-anchor" href="#盖可保险挑战" aria-label="Permalink to &quot;盖可保险挑战&quot;">​</a></h2><h3 id="增长停滞" tabindex="-1">增长停滞 <a class="header-anchor" href="#增长停滞" aria-label="Permalink to &quot;增长停滞&quot;">​</a></h3><ul><li>新业务获取成本急剧上升</li><li>咨询转化率多年来首次下降</li><li>竞争对手州立农业保险公司愿意承受18%承保亏损</li></ul><h3 id="应对措施" tabindex="-1">应对措施 <a class="header-anchor" href="#应对措施" aria-label="Permalink to &quot;应对措施&quot;">​</a></h3><ul><li>削减不符合成本效益的广告</li><li>积极申请必要地区的费率上调</li><li>利润分享支付4,070万美元（占工资8.8%）</li></ul><h2 id="投资理念-伊索寓言" tabindex="-1">投资理念：伊索寓言 <a class="header-anchor" href="#投资理念-伊索寓言" aria-label="Permalink to &quot;投资理念：伊索寓言&quot;">​</a></h2><h3 id="一鸟在手胜过二鸟在林" tabindex="-1">&quot;一鸟在手胜过二鸟在林&quot; <a class="header-anchor" href="#一鸟在手胜过二鸟在林" aria-label="Permalink to &quot;&quot;一鸟在手胜过二鸟在林&quot;&quot;">​</a></h3><p>三个关键问题：</p><ol><li>有多确定林中确实有鸟？</li><li>它们何时会出现，会有多少？</li><li>无风险利率是多少？</li></ol><h3 id="核心观点" tabindex="-1">核心观点 <a class="header-anchor" href="#核心观点" aria-label="Permalink to &quot;核心观点&quot;">​</a></h3><ul><li>增长只是价值方程的组成部分，有时是加号，有时是减号</li><li>常见衡量标准（股息收益率、市盈率、增长率）与估值无关</li><li>除非提供现金流入流出的线索</li></ul><h2 id="市场泡沫批评" tabindex="-1">市场泡沫批评 <a class="header-anchor" href="#市场泡沫批评" aria-label="Permalink to &quot;市场泡沫批评&quot;">​</a></h2><h3 id="非理性预期" tabindex="-1">非理性预期 <a class="header-anchor" href="#非理性预期" aria-label="Permalink to &quot;非理性预期&quot;">​</a></h3><ul><li>投资者预期未来十年年回报率19%</li><li>泡沫市场允许创建泡沫公司</li><li>IPO而非利润成为主要目标</li></ul><h3 id="投机危害" tabindex="-1">投机危害 <a class="header-anchor" href="#投机危害" aria-label="Permalink to &quot;投机危害&quot;">​</a></h3><ul><li>投机在最容易时最危险</li><li>财富从公众转移到发起人</li><li>真正的价值创造需要盈利的企业</li></ul><h2 id="收购哲学" tabindex="-1">收购哲学 <a class="header-anchor" href="#收购哲学" aria-label="Permalink to &quot;收购哲学&quot;">​</a></h2><h3 id="为什么卖家选择伯克希尔" tabindex="-1">为什么卖家选择伯克希尔 <a class="header-anchor" href="#为什么卖家选择伯克希尔" aria-label="Permalink to &quot;为什么卖家选择伯克希尔&quot;">​</a></h3><ul><li>关心卖给谁，而非仅仅是金钱</li><li>希望企业文化得以延续</li><li>伯克希尔提供&quot;几乎独一无二的家&quot;</li></ul><h3 id="收购承诺" tabindex="-1">收购承诺 <a class="header-anchor" href="#收购承诺" aria-label="Permalink to &quot;收购承诺&quot;">​</a></h3><ul><li>业务继续在原地运营</li><li>不与其他公司合并</li><li>所有权结构确保承诺能够履行</li></ul><h2 id="主要持仓" tabindex="-1">主要持仓 <a class="header-anchor" href="#主要持仓" aria-label="Permalink to &quot;主要持仓&quot;">​</a></h2><ul><li>可口可乐：121.88亿美元</li><li>美国运通：83.29亿美元</li><li>吉列：34.68亿美元</li><li>富国银行：30.67亿美元</li></ul><h2 id="其他要点" tabindex="-1">其他要点 <a class="header-anchor" href="#其他要点" aria-label="Permalink to &quot;其他要点&quot;">​</a></h2><ul><li>出售几乎所有房地美和房利美股份</li><li>购买高收益债券和抵押贷款支持证券</li><li>总部员工13.8人，管理400亿美元收入</li><li>拉尔夫·谢伊退休，15年向伯克希尔分配10.3亿美元</li></ul><hr><p><em>核心要点总结完成</em></p>',40)])])}const b=l(r,[["render",o]]);export{q as __pageData,b as default};
